import{_ as e,o as d,c as o,a2 as a}from"./chunks/framework.DvFsUg-r.js";const g=JSON.parse('{"title":"Hexo 블로그 임포트 — Data Model (Phase 1)","description":"","frontmatter":{"title":"Hexo 블로그 임포트 — Data Model (Phase 1)","feature_id":"008","created":"2026-06-02 15:12 (KST)","date":"2026-06-02T00:00:00.000Z"},"headers":[],"relativePath":"specs/008-hexo-blog-import/data-model.md","filePath":"specs/008-hexo-blog-import/data-model.md","lastUpdated":null}'),r={name:"specs/008-hexo-blog-import/data-model.md"};function c(s,t,i,n,l,h){return d(),o("div",null,[...t[0]||(t[0]=[a(`<h1 id="data-model-hexo-→-vitepress-임포트" tabindex="-1">Data Model: Hexo → VitePress 임포트 <a class="header-anchor" href="#data-model-hexo-→-vitepress-임포트" aria-label="Permalink to &quot;Data Model: Hexo → VitePress 임포트&quot;">​</a></h1><p>런타임 DB 가 아니라 <strong>변환 파이프라인이 다루는 인메모리 엔티티</strong>다.</p><h2 id="sourcepost-소스-게시글" tabindex="-1">SourcePost (소스 게시글) <a class="header-anchor" href="#sourcepost-소스-게시글" aria-label="Permalink to &quot;SourcePost (소스 게시글)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>필드</th><th>타입</th><th>설명</th></tr></thead><tbody><tr><td><code>srcPath</code></td><td>string</td><td><code>source/_posts/**/X.md</code> 절대경로</td></tr><tr><td><code>slug</code></td><td>string</td><td>파일명(확장자 제외) → URL/파일 슬러그</td></tr><tr><td><code>title</code></td><td>string</td><td>Hexo frontmatter <code>title</code> (없으면 slug)</td></tr><tr><td><code>date</code></td><td>Date</td><td>Hexo <code>date</code> 파싱(없으면 파일 mtime)</td></tr><tr><td><code>categories</code></td><td>string[]</td><td>폴더 경로 + frontmatter <code>categories</code> 합집합</td></tr><tr><td><code>tags</code></td><td>string[]</td><td>frontmatter <code>tags</code> (선택)</td></tr><tr><td><code>body</code></td><td>string</td><td>프런트매터 제거 후 본문(변환 전 원문)</td></tr><tr><td><code>assetDir</code></td><td>string?</td><td>post_asset_folder 규칙상 동명 폴더(있으면)</td></tr></tbody></table><p><strong>파생 규칙</strong></p><ul><li><code>categoryKey</code> = 첫 카테고리(정규화 소문자 경로). 빈 값 → <code>uncategorized</code>.</li><li><code>outPath</code> = <code>blog-archive/&lt;categoryKey&gt;/&lt;slug&gt;.md</code>.</li><li>정렬 키 = <code>date</code> 내림차순(동률 시 slug 오름차순).</li></ul><h2 id="imageref-이미지-참조" tabindex="-1">ImageRef (이미지 참조) <a class="header-anchor" href="#imageref-이미지-참조" aria-label="Permalink to &quot;ImageRef (이미지 참조)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>필드</th><th>타입</th><th>설명</th></tr></thead><tbody><tr><td><code>rawRef</code></td><td>string</td><td>본문 원문 참조(<code>![](../../images/x.jpg)</code> 또는 <code>{% asset_img x.png %}</code>)</td></tr><tr><td><code>kind</code></td><td>enum</td><td><code>markdown</code> | <code>asset_img</code></td></tr><tr><td><code>resolvedSrc</code></td><td>string?</td><td>실제 원본 파일 절대경로(해석 성공 시)</td></tr><tr><td><code>outRel</code></td><td>string</td><td>글 기준 상대 출력경로 <code>./&lt;slug&gt;.assets/&lt;file&gt;</code></td></tr><tr><td><code>status</code></td><td>enum</td><td><code>copied</code> | <code>missing</code></td></tr></tbody></table><p><strong>해석 순서</strong>: ① 글 <code>assetDir</code> → ② 전역 <code>source/images/</code>·<code>source/img/</code> → ③ <code>srcPath</code> 기준 상대경로(<code>../../images/...</code>) 정규화. 모두 실패 → <code>missing</code> (빌드 깨지 않게 링크는 남기되 리포트에 집계).</p><h2 id="hexotag-변환-대상-태그" tabindex="-1">HexoTag (변환 대상 태그) <a class="header-anchor" href="#hexotag-변환-대상-태그" aria-label="Permalink to &quot;HexoTag (변환 대상 태그)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>필드</th><th>타입</th><th>설명</th></tr></thead><tbody><tr><td><code>name</code></td><td>enum</td><td><code>asset_img</code>|<code>fa</code>|<code>callout</code>|<code>iframe</code>|<code>drawio</code>|<code>incl</code>|<code>raw</code>|<code>unknown</code></td></tr><tr><td><code>args</code></td><td>string</td><td>원문 인자 문자열</td></tr><tr><td><code>replacement</code></td><td>string</td><td>VitePress 등가 출력(또는 빈 문자열)</td></tr></tbody></table><p>상세 변환표 → <a href="./contracts/transform-rules">contracts/transform-rules.md</a>.</p><h2 id="categorygroup-사이드바-그룹" tabindex="-1">CategoryGroup (사이드바 그룹) <a class="header-anchor" href="#categorygroup-사이드바-그룹" aria-label="Permalink to &quot;CategoryGroup (사이드바 그룹)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>필드</th><th>타입</th><th>설명</th></tr></thead><tbody><tr><td><code>key</code></td><td>string</td><td>정규화 카테고리 경로</td></tr><tr><td><code>label</code></td><td>string</td><td><strong>영문</strong> 표시 라벨(매핑표/Title Case)</td></tr><tr><td><code>items</code></td><td>{text,link}[]</td><td>소속 글, <code>date</code> 내림차순</td></tr></tbody></table><p>→ <code>.vitepress/blog-archive-sidebar.mts</code> 의 <code>&#39;/blog-archive/&#39;</code> 키 배열로 직렬화.</p><h2 id="importreport-실행-리포트" tabindex="-1">ImportReport (실행 리포트) <a class="header-anchor" href="#importreport-실행-리포트" aria-label="Permalink to &quot;ImportReport (실행 리포트)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>필드</th><th>타입</th><th>설명</th></tr></thead><tbody><tr><td><code>postsConverted</code></td><td>number</td><td>변환 성공 글 수</td></tr><tr><td><code>imagesCopied</code></td><td>number</td><td>복사된 이미지 수</td></tr><tr><td><code>imagesMissing</code></td><td>{post,ref}[]</td><td>해석 실패 이미지</td></tr><tr><td><code>includesExpanded</code></td><td>number</td><td>인라인 전개된 include 수</td></tr><tr><td><code>includesMissing</code></td><td>{post,name}[]</td><td>미발견 include</td></tr><tr><td><code>tagsUnknown</code></td><td>{post,tag}[]</td><td>변환 못한 잔여 태그(있으면 SC-8 위반)</td></tr><tr><td><code>skipped</code></td><td>{path,reason}[]</td><td>비대상/오류로 건너뛴 항목</td></tr></tbody></table><p>콘솔 요약 + <code>blog-archive/.import-report.json</code>(git 무시) 으로 출력.</p><h2 id="상태-전이-글-1건-파이프라인" tabindex="-1">상태 전이 (글 1건 파이프라인) <a class="header-anchor" href="#상태-전이-글-1건-파이프라인" aria-label="Permalink to &quot;상태 전이 (글 1건 파이프라인)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>discover → parseFrontmatter → mapCategory → expandIncludes</span></span>
<span class="line"><span>  → convertTags → resolveImages(copy) → sanitizeVue → writeOutput</span></span>
<span class="line"><span>  → indexEntry(+sidebar)</span></span></code></pre></div><p>실패 단계는 해당 글을 <code>skipped</code>/부분복구 처리하되 <strong>전체 실행은 계속</strong>한다.</p>`,21)])])}const m=e(r,[["render",c]]);export{g as __pageData,m as default};
